{
  "id": "typeference/typeference-maintainer@0.1.0",
  "displayName": "TypeFerence Maintainer",
  "description": "The agent that maintains the TypeFerence repository, defined in TypeFerence\u0027s own terms and compiled into this repository\u0027s AGENTS.md.",
  "emit": true,
  "embeds": [
    "typeference/profiles/spec-conformance@0.1.0",
    "typeference/profiles/determinism-guardian@0.1.0",
    "typeference/profiles/trust-signing@0.1.0",
    "typeference/profiles/contribution-workflow@0.1.0"
  ],
  "satisfies": [],
